using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Serialization;

/// <summary>
/// "Banco de dados" do progresso do jogador: vida, recursos, inventário, animais
/// libertados, upgrades, modo de jogo e progressão por área/mundo.
///
/// As condições de eventos de NPC (Etapa 1) leem este estado através de
/// PlayerProgress.Instance, e as ações de recompensa (Etapa 5) escrevem nele.
/// </summary>
public partial class PlayerProgress : MonoBehaviour
{
    public static PlayerProgress Instance { get; private set; }

    [Header("Vida")]
    public int currentHearts = 6;
    public int maxHearts = 6;

    /// <summary>Número máximo de corações (recipientes), mesmo com Fragmentos Vitais extra (GDD: limite de 12 corações).</summary>
    public const int MaxHeartsCap = 12;

    [Header("Recursos")]
    public int sementes;
    public int runasDeGaia;
    public int brotosDeVida;
    public int fragmentosVitais;

    [Tooltip("Runas de Apolo recolhidas (0–6). Ao atingir 6, o EmblemManager desbloqueia o Emblema de Apolo + Aura de Fogo.")]
    public int runasDeApolo;

    [Tooltip("Saldo de Ecos Perdidos disponíveis para comprar Sussurros da Terra no Contador de Histórias.")]
    public int ecosPerdidos;

    [Tooltip("Total de Runas de Gaia recolhidas ao longo do jogo (nunca desce, mesmo ao gastar). 'runasDeGaia' acima é o saldo disponível/gasto.")]
    public int totalRunasDeGaiaCollected;

    [Header("Fragmentos Vitais → Corações")]
    [Tooltip("Quantos Fragmentos Vitais são necessários para desbloquear +1 coração extra (recipiente), até ao limite de MaxHeartsCap (12). GDD: 3 Fragmentos Vitais = +1 coração. 0 = conversão desactivada.")]
    [SerializeField] private int fragmentsPerHeart = 3;

    [Header("Inventário (com quantidades — Etapa 4.2)")]
    [SerializeField] private List<InventoryEntry> _inventory = new List<InventoryEntry>();
    public IReadOnlyList<InventoryEntry> inventory => _inventory;
    public string equippedItemId;

    [Header("Itens Especiais Já Recolhidos (drops únicos — Etapa 4.3)")]
    [Tooltip("IDs de itens especiais registados permanentemente como colectados (ItemData.savedAsCollected / dropsOnlyOnce). Não saem desta lista mesmo que o item seja removido do inventário.")]
    [SerializeField] private List<string> _collectedSpecialItemIds = new List<string>();
    public IReadOnlyList<string> collectedSpecialItemIds => _collectedSpecialItemIds;

    [Header("Coleccionáveis do Mundo Já Recolhidos (Pickups)")]
    [Tooltip("IDs persistentes (PickupBase.pickupId) de coleccionáveis do mundo (Runas, Sementes, Fragmentos, Brotos, Sussurros, baús, recompensas de missão, ...) já recolhidos — impede recolha duplicada (ex: ao voltar à área ou recarregar um save).")]
    [SerializeField] private List<string> _collectedPickupIds = new List<string>();
    public IReadOnlyList<string> collectedPickupIds => _collectedPickupIds;

    [Header("Contadores Globais de Coleccionáveis")]
    [Tooltip("Total de Sementes recolhidas ao longo do jogo (nunca desce, mesmo ao gastar).")]
    public int totalSementesCollected;

    [Tooltip("Total de Fragmentos Vitais recolhidos ao longo do jogo (nunca desce — distinto de 'fragmentosVitais', que é consumido na conversão em corações extra).")]
    public int totalFragmentosVitaisCollected;

    [Tooltip("Total de Brotos de Vida recolhidos ao longo do jogo (nunca desce).")]
    public int totalBrotosDeVidaCollected;

    [Tooltip("Total de Ecos Perdidos recolhidos ao longo do jogo (nunca desce, mesmo ao gastar).")]
    public int totalEcosPerdidosCollected;

    [Tooltip("Total de Sussurros da Terra encontrados em todas as áreas (soma de AreaProgress.whispersFound).")]
    public int totalSussurrosCollected;

    [Tooltip("Total de baús abertos em todas as áreas (soma de AreaProgress.chestsFound).")]
    public int totalChestsOpenedGlobal;

    [Header("Inimigos Derrotados Permanentemente (Etapa 7.3)")]
    [Tooltip("IDs de persistência de inimigos especiais/mini-bosses derrotados que nunca respawnam (EnemyRespawn).")]
    [SerializeField] private List<string> _defeatedEnemyIds = new List<string>();
    public IReadOnlyList<string> defeatedEnemyIds => _defeatedEnemyIds;

    [Header("Melodias Selvagens")]
    [Tooltip("IDs (WildMelodyData.melodyId) de Melodias Selvagens já colectadas. Cada melodia conta para a % de conclusão da sua área e do save.")]
    [SerializeField] private List<string> _collectedMelodyIds = new List<string>();
    public IReadOnlyList<string> collectedMelodyIds => _collectedMelodyIds;

    [Header("Desafios (Sistema de Missões/Desafios)")]
    [Tooltip("IDs (ChallengeDefinition.challengeId) de desafios já concluídos pelo menos uma vez — controla recompensa primária única vs. secundária em repetições.")]
    [SerializeField] private List<string> _completedChallengeIds = new List<string>();
    public IReadOnlyList<string> completedChallengeIds => _completedChallengeIds;

    [Tooltip("Melhores tempos registados por desafio (apenas desafios com 'hasTimeLimit') — ranking/recordes pessoais.")]
    [SerializeField] private List<ChallengeRecord> _challengeRecords = new List<ChallengeRecord>();
    public IReadOnlyList<ChallengeRecord> challengeRecords => _challengeRecords;

    [Header("Animais e Upgrades")]
    [SerializeField] private List<string> _freedAnimalIds = new List<string>();
    public IReadOnlyList<string> freedAnimalIds => _freedAnimalIds;
    [SerializeField] private List<string> _unlockedUpgradeIds = new List<string>();
    public IReadOnlyList<string> unlockedUpgradeIds => _unlockedUpgradeIds;

    [Tooltip("IDs de upgrades 'Instinto' (UpgradeData.toggleable) actualmente LIGADOS. Upgrades não-toggleable ficam sempre activos depois de desbloqueados, independentemente desta lista.")]
    [SerializeField] private List<string> _enabledUpgradeIds = new List<string>();
    public IReadOnlyList<string> enabledUpgradeIds => _enabledUpgradeIds;

    [Header("Checkpoint")]
    [Tooltip("ID do último Refúgio Seguro (SafeHaven) usado — checkpoint para reaparecimento/contexto de save.")]
    public string lastCheckpointId;

    // Checkpoint temporário (Checkpoint.cs — ex: início de área, Caminho do
    // Ferimento): NÃO persistido no save (sessão actual apenas). Tem prioridade
    // sobre "lastCheckpointId" enquanto o jogador permanecer na mesma área.
    private bool hasTemporaryCheckpoint;
    private Vector2 temporaryCheckpointPosition;
    private string temporaryCheckpointAreaId;

    [Header("Progressão por Área")]
    [SerializeField] private List<AreaProgress> areaProgress = new List<AreaProgress>();

    [Header("Progressão por Mundo (Bosses)")]
    [SerializeField] private List<string> defeatedBossWorldIds = new List<string>();
    [SerializeField] private List<string> pendingPostBossReturnWorldIds = new List<string>();

    [Header("Progressão por Mundo (Menu de Pausa: Progresso — Tarefa #11)")]
    [SerializeField] private List<WorldProgress> worldProgress = new List<WorldProgress>();

    [Header("Mapa-Múndi — Áreas Desbloqueadas")]
    [Tooltip("areaId (AreaData.areaId) de cada área já desbloqueada no Mapa-Múndi (botão \"Desbloquear\" pago, vila auto-desbloqueada, ou área de boss liberta pela missão principal). Controla o estado bloqueado/desbloqueado de cada WorldMapNode e quais caminhos a bola de luz pode atravessar.")]
    [SerializeField] private List<string> unlockedAreaIds = new List<string>();

    [Header("Mapa-Múndi — Bosses")]
    [Tooltip("worldId (WorldData.worldId) dos mundos cujo boss já foi encontrado pelo menos uma vez (vitória OU derrota). A partir daqui o painel da área do boss mostra AreaData.bossDisplayName em vez de \"????????\".")]
    [SerializeField] private List<string> discoveredBossWorldIds = new List<string>();

    [Tooltip("worldId (WorldData.worldId) dos mundos cuja animação de desbloqueio da área do boss (câmara viaja até à Coroa, novo ramo ilumina-se) já foi reproduzida. Garante que a animação só acontece uma vez.")]
    [SerializeField] private List<string> bossUnlockAnimationPlayedWorldIds = new List<string>();

    [Header("Diário — Pistas de Missão e Rumores (Sistema de Pistas/Rumores)")]
    [Tooltip("IDs combinados (\"<missionId>/<clueId>\") de pistas (MissionData.clues) já obtidas — mostradas na sub-secção \"Pistas\" de cada missão no Diário.")]
    [SerializeField] private List<string> _obtainedClueIds = new List<string>();
    public IReadOnlyList<string> obtainedClueIds => _obtainedClueIds;

    [Tooltip("IDs (RumorData.rumorId) de rumores já ouvidos — aparecem permanentemente na secção \"Rumores\" do Diário.")]
    [SerializeField] private List<string> _heardRumorIds = new List<string>();
    public IReadOnlyList<string> heardRumorIds => _heardRumorIds;

    [Tooltip("IDs (RumorData.rumorId) de rumores já marcados como \"encontrados\" (Action_MarkRumorFound) — mostram um ícone de \"Check\" junto ao rumor, sem o remover da lista.")]
    [SerializeField] private List<string> _foundRumorIds = new List<string>();
    public IReadOnlyList<string> foundRumorIds => _foundRumorIds;

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar — nunca configuradas no Inspector.
    ///
    /// Sem isto, se a cena também tiver a sua própria instância (configurada),
    /// o Awake() dessa instância encontraria "Instance" já preenchido (pela
    /// versão vazia auto-criada) e destruir-se-ia a si próprio, perdendo toda a
    /// configuração feita no Inspector (Tarefa #15 — "GameBootstrap e
    /// singletons"). Em vez disso, quando uma instância "real" (não-fallback)
    /// faz Awake() e encontra um fallback como Instance, é o fallback que é
    /// destruído — a instância real é que fica.
    ///
    /// Recomendação de organização (opcional, sem impacto no código): manter
    /// as 7 instâncias configuradas (PlayerProgress, GameVariables,
    /// MissionManager, WorldState, AudioManager, SaveManager, GameSettings)
    /// num único GameObject "GameBootstrap" (com DontDestroyOnLoad) presente
    /// apenas na primeira cena do jogo — um único sítio para configurar tudo.
    /// O isAutoFallback acima continua a servir de rede de segurança caso o
    /// jogo seja iniciado por outra cena (ex: testes a meio do jogo).
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        // Tarefa #22 (Menu Inicial — "Novo Jogo"): guarda uma fotografia dos
        // valores configurados no Inspector para esta instância, ainda antes
        // de qualquer progresso ser feito. ResetForNewGame() restaura a partir
        // daqui, sem precisar de destruir o singleton (que outros sistemas já
        // referenciam via Instance).
        _initialSnapshotJson = JsonUtility.ToJson(this);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(PlayerProgress) + " (Fallback)");
        var instance = go.AddComponent<PlayerProgress>();
        instance.isAutoFallback = true;
    }

    // ---------------- Novo Jogo (Tarefa #22) ----------------

    private string _initialSnapshotJson;

    /// <summary>
    /// Repõe todo o progresso (vida, recursos, inventário, coleccionáveis,
    /// animais/upgrades, checkpoints) para os valores configurados no Inspector
    /// no arranque — usado por <see cref="MainMenuController"/> ao escolher
    /// "Novo Jogo". Dispara os eventos de mudança relevantes para a UI (HUD,
    /// menus) se actualizar de imediato.
    /// </summary>
    public void ResetForNewGame()
    {
        if (!string.IsNullOrEmpty(_initialSnapshotJson))
            JsonUtility.FromJsonOverwrite(_initialSnapshotJson, this);

        hasTemporaryCheckpoint = false;
        _snapshots.Clear();

        HealthChanged?.Invoke(currentHearts, maxHearts);
        SeedsChanged?.Invoke(sementes);
        RunasChanged?.Invoke(runasDeGaia, totalRunasDeGaiaCollected);
        EquippedItemChanged?.Invoke(equippedItemId);
    }

    // ---------------- NG+ (Tarefa #33) ----------------

    [Header("NG+ (Tarefa #33)")]
    [Tooltip("True enquanto esta partida é uma New Game Plus (iniciada via StartNewGamePlus). Usado por sistemas que queiram mostrar conteúdo especial de NG+ ou adaptar a dificuldade.")]
    [SerializeField] private bool isNewGamePlus;

    [Tooltip("Nomes das variáveis globais (GameVariables) que devem ser PRESERVADAS entre NG+: tipicamente as variáveis 'obtainedVariable' dos Emblemas de Gaia, Apolo e Zeus. Preencher no Inspector com os nomes exactos das variáveis.")]
    [SerializeField] private List<string> ngPlusPreservedEmblemVariables = new List<string>();

    /// <summary>True enquanto esta partida é um New Game Plus.</summary>
    public bool IsNewGamePlus => isNewGamePlus;

    /// <summary>
    /// Inicia um New Game Plus (Tarefa #33): preserva animais libertados,
    /// upgrades e variáveis de emblemas globais (Gaia/Apolo/Zeus), repõe
    /// todo o resto para os valores iniciais, e marca <see cref="IsNewGamePlus"/>.
    ///
    /// Sequência:
    /// 1. Guarda listas de progresso e variáveis a preservar.
    /// 2. Chama <see cref="ResetForNewGame"/> (repõe tudo).
    /// 3. Restaura as listas preservadas.
    /// 4. Seta isNewGamePlus = true.
    ///
    /// Chamado por <see cref="MainMenuController"/> quando o jogador confirma
    /// "New Game+" (visível apenas quando <see cref="IsPostGameRewardActive"/> é true).
    /// </summary>
    public void StartNewGamePlus()
    {
        // 1. Preservar progresso a partir dos dados em memória.
        var savedFreedAnimalIds = new System.Collections.Generic.List<string>(_freedAnimalIds);
        var savedUnlockedUpgradeIds = new System.Collections.Generic.List<string>(_unlockedUpgradeIds);
        var savedEnabledUpgradeIds = new System.Collections.Generic.List<string>(_enabledUpgradeIds);

        ApplyNewGamePlus(savedFreedAnimalIds, savedUnlockedUpgradeIds, savedEnabledUpgradeIds);
    }

    /// <summary>
    /// Inicia um New Game+ copiando os dados preservados directamente de um
    /// SaveData (ex: o autosave) em vez dos dados actualmente em memória.
    ///
    /// Task 1.1: ao iniciar pelo menu principal, a memória está nos valores
    /// iniciais (listas vazias), por isso é obrigatório usar este método em vez
    /// de <see cref="StartNewGamePlus"/> — garante que os animais, upgrades e
    /// emblemas do save são preservados mesmo que ainda não tenham sido
    /// aplicados à instância em memória.
    /// </summary>
    public void StartNewGamePlusFromSave(SaveData sourceSave)
    {
        if (sourceSave == null)
        {
            Debug.LogWarning("[PlayerProgress] StartNewGamePlusFromSave: sourceSave é null — a usar dados em memória.");
            StartNewGamePlus();
            return;
        }

        var savedFreedAnimalIds = sourceSave.freedAnimalIds != null
            ? new System.Collections.Generic.List<string>(sourceSave.freedAnimalIds)
            : new System.Collections.Generic.List<string>();

        var savedUnlockedUpgradeIds = sourceSave.unlockedUpgradeIds != null
            ? new System.Collections.Generic.List<string>(sourceSave.unlockedUpgradeIds)
            : new System.Collections.Generic.List<string>();

        var savedEnabledUpgradeIds = sourceSave.enabledUpgradeIds != null
            ? new System.Collections.Generic.List<string>(sourceSave.enabledUpgradeIds)
            : new System.Collections.Generic.List<string>();

        // Ler variáveis de emblemas do save (GameVariables não está carregado ainda).
        var savedEmblemValues = new System.Collections.Generic.Dictionary<string, bool>();
        var vars = GameVariables.Instance;
        if (vars != null && ngPlusPreservedEmblemVariables != null)
        {
            // Preferir estado actual do save se GameVariables ainda não foi restaurado;
            // como não temos um SaveData.gameVariables separado facilmente acessível,
            // usamos os valores actuais da instância (que podem ser padrão neste ponto).
            // A restauração de GameVariables ocorre antes desta chamada em MainMenuController.
            foreach (var varName in ngPlusPreservedEmblemVariables)
                if (!string.IsNullOrEmpty(varName))
                    savedEmblemValues[varName] = vars.GetBool(varName);
        }

        ApplyNewGamePlus(savedFreedAnimalIds, savedUnlockedUpgradeIds, savedEnabledUpgradeIds, savedEmblemValues);
    }

    private void ApplyNewGamePlus(
        System.Collections.Generic.List<string> savedFreedAnimalIds,
        System.Collections.Generic.List<string> savedUnlockedUpgradeIds,
        System.Collections.Generic.List<string> savedEnabledUpgradeIds,
        System.Collections.Generic.Dictionary<string, bool> savedEmblemValues = null)
    {
        // Preservar variáveis de emblemas (se não fornecido externamente, ler da memória).
        var vars = GameVariables.Instance;
        if (savedEmblemValues == null)
        {
            savedEmblemValues = new System.Collections.Generic.Dictionary<string, bool>();
            if (vars != null && ngPlusPreservedEmblemVariables != null)
            {
                foreach (var varName in ngPlusPreservedEmblemVariables)
                    if (!string.IsNullOrEmpty(varName))
                        savedEmblemValues[varName] = vars.GetBool(varName);
            }
        }

        // Repor tudo (novo jogo).
        ResetForNewGame();
        vars?.ResetForNewGame();

        // Restaurar progresso preservado.
        _freedAnimalIds = savedFreedAnimalIds;
        _unlockedUpgradeIds = savedUnlockedUpgradeIds;
        _enabledUpgradeIds = savedEnabledUpgradeIds;

        // GDD v2: NG+ NÃO preserva a Recompensa de Pós-Jogo.
        _unlockedUpgradeIds.Remove(RecompensaPosJogoUpgradeId);
        _enabledUpgradeIds.Remove(RecompensaPosJogoUpgradeId);

        // Restaurar variáveis de emblemas.
        if (vars != null)
            foreach (var kv in savedEmblemValues)
                vars.SetBool(kv.Key, kv.Value);

        // Marcar como NG+.
        isNewGamePlus = true;
    }

    // ---------------- Vida ----------------

    /// <summary>
    /// Disparado quando "currentHearts" chega a 0 pela primeira vez (transição
    /// de &gt;0 para 0) — Tarefa #16, "tela de morte". PlayerDeathHandler
    /// liga-se aqui para iniciar a sequência de morte/reaparecimento.
    /// </summary>
    public event System.Action OnHeartsDepleted;

    /// <summary>Disparado sempre que "currentHearts" ou "maxHearts" mudam — UI (HUD de corações) pode ligar-se aqui em vez de pollar todos os frames.</summary>
    public event System.Action<int, int> HealthChanged;

    /// <summary>
    /// Dispara <see cref="HealthChanged"/> com os valores actuais. Para código
    /// externo que altera currentHearts/maxHearts directamente (ex:
    /// Action_RestorePlayerSnapshot) — eventos C# só podem ser invocados
    /// dentro da classe que os declara.
    /// </summary>
    public void NotifyHealthChanged() => HealthChanged?.Invoke(currentHearts, maxHearts);

    /// <summary>Disparado sempre que "sementes" muda.</summary>
    public event System.Action<int> SeedsChanged;

    /// <summary>Disparado sempre que "ecosPerdidos" muda — (saldo actual).</summary>
    public event System.Action<int> EcosPerdidosChanged;

    /// <summary>Disparado sempre que o saldo/total de Runas de Gaia muda — (saldo disponível, total histórico recolhido).</summary>
    public event System.Action<int, int> RunasChanged;

    /// <summary>
    /// Disparado no final de <see cref="RestoreFrom"/> depois de todo o estado
    /// ter sido reposto a partir de um save. As interfaces que exibem múltiplos
    /// campos (HUD completo, menu de pausa, secções de progresso) podem subscrever
    /// aqui e reler o estado completo de uma vez, em vez de subscreverem cada
    /// evento individual. Disparado também por <see cref="ResetForNewGame"/>.
    /// </summary>
    public event System.Action StateRestored;

    /// <summary>Disparado quando uma forma animal é libertada por "formId" pela primeira vez (não repete para formas já libertadas).</summary>
    public event System.Action<string> AnimalUnlocked;

    /// <summary>Disparado quando uma área é desbloqueada no Mapa-Múndi (paga, vila auto-desbloqueada, ou boss libertado) — "areaId" da área desbloqueada. WorldMapUI/WorldMapController podem ligar-se aqui para actualizar os nós/caminhos visíveis.</summary>
    public event System.Action<string> AreaUnlockedOnMap;

    /// <summary>
    /// Disparado sempre que Fragmentos Vitais acumulados são convertidos num
    /// novo recipiente de coração (TryConvertFragments) — sistemas de UI/VFX/SFX
    /// podem ligar-se aqui para tocar a animação/som de "novo coração", em vez
    /// de depender só de HealthChanged (que também dispara em dano/cura normais).
    /// </summary>
    public event System.Action HeartContainerGained;

    /// <summary>
    /// Disparado quando um coleccionável do mundo (PickupBase e subclasses —
    /// Runa, Semente, Fragmento, Broto, Sussurro, baú, recompensa de missão)
    /// é recolhido. UI/SFX/estatísticas podem ligar-se aqui em vez de cada
    /// pickup ter de conhecer directamente esses sistemas. Não concede a
    /// recompensa em si — isso já foi feito pelo Give*/Add* específico antes
    /// deste evento ser disparado.
    /// </summary>
    public event System.Action<PickupType, string> PickupCollected;

    public bool HasFewerHeartsThan(int x) => currentHearts < x;
    public bool HasMoreHeartsThan(int x) => currentHearts > x;

    public void Heal(int amount)
    {
        currentHearts = Mathf.Clamp(currentHearts + amount, 0, maxHearts);
        HealthChanged?.Invoke(currentHearts, maxHearts);
    }

    public void Damage(int amount)
    {
        bool wasAlive = currentHearts > 0;
        currentHearts = Mathf.Clamp(currentHearts - amount, 0, maxHearts);
        HealthChanged?.Invoke(currentHearts, maxHearts);

        if (wasAlive && currentHearts <= 0)
            OnHeartsDepleted?.Invoke();
    }

    // ---------------- Recursos ----------------

    public bool HasSementes(int amount) => sementes >= amount;
    public bool HasRunasDeGaia(int amount) => runasDeGaia >= amount;

    /// <summary>Saldo actual do recurso indicado (Sementes/Runas de Gaia/Brotos de Vida/Fragmentos Vitais).</summary>
    public int GetResourceAmount(PlayerResourceType resource)
    {
        switch (resource)
        {
            case PlayerResourceType.Sementes: return sementes;
            case PlayerResourceType.RunasDeGaia: return runasDeGaia;
            case PlayerResourceType.BrotosDeVida: return brotosDeVida;
            case PlayerResourceType.FragmentosVitais: return fragmentosVitais;
            case PlayerResourceType.EcosPerdidos: return ecosPerdidos;
            default: return 0;
        }
    }

    /// <summary>True se o jogador tem pelo menos "amount" do recurso indicado.</summary>
    public bool HasResource(PlayerResourceType resource, int amount) => GetResourceAmount(resource) >= amount;

    /// <summary>
    /// Tenta gastar "amount" do recurso indicado (ex: compra de upgrade —
    /// Action_BuyUpgrade). Se o saldo for insuficiente, não altera nada e
    /// devolve false. "amount" &lt;= 0 não gasta nada e devolve true.
    /// </summary>
    public bool TrySpendResource(PlayerResourceType resource, int amount)
    {
        if (amount <= 0) return true;
        if (!HasResource(resource, amount)) return false;

        switch (resource)
        {
            case PlayerResourceType.Sementes: GiveSementes(-amount); break;
            case PlayerResourceType.RunasDeGaia: GiveRunasDeGaia(-amount); break;
            case PlayerResourceType.BrotosDeVida: GiveBrotosDeVida(-amount); break;
            case PlayerResourceType.FragmentosVitais: GiveFragmentosVitais(-amount); break;
            case PlayerResourceType.EcosPerdidos: GiveEcosPerdidos(-amount); break;
        }

        return true;
    }

    public void GiveSementes(int amount)
    {
        sementes = Mathf.Max(0, sementes + amount);
        if (amount > 0) totalSementesCollected += amount;
        SeedsChanged?.Invoke(sementes);
    }

    /// <summary>
    /// Disparado a cada tick da animação de sementes iniciada por um evento de
    /// NPC (Action_GiveSementesAnimated / Action_TakeSementesAnimated) —
    /// contém o valor de exibição temporário (ainda não é o saldo real).
    ///
    /// A HUD de Sementes deve subscrever aqui para mostrar o número animado.
    /// Ao fim da animação, GiveSementes é chamado e SeedsChanged dispara com o
    /// valor real final — a HUD deve voltar ao saldo real a partir daí.
    /// </summary>
    public event System.Action<int> SeedsAnimationTick;

    /// <summary>
    /// Dispara SeedsAnimationTick com "displayValue" — chamado pela acção NPC
    /// a cada frame durante a animação de contagem. Não altera o saldo real.
    /// </summary>
    public void FireSeedsAnimationTick(int displayValue)
        => SeedsAnimationTick?.Invoke(displayValue);

    /// <summary>
    /// Força SeedsChanged com o saldo actual (sem alterar o valor) — usado por
    /// Action_ShowSementes para garantir que a HUD mostra o valor real correcto
    /// antes de uma sequência animada.
    /// </summary>
    public void RefreshSeedsDisplay() => SeedsChanged?.Invoke(sementes);

    /// <summary>
    /// Ajusta o saldo de Sementes SEM disparar SeedsChanged (sem animação HUD,
    /// sem feedback visual). Usado pelas acções NPC "silenciosas" — ex: retirar
    /// sementes em background sem o player ver o número mudar.
    /// O total colectado (totalSementesCollected) continua a ser actualizado.
    /// </summary>
    public void GiveSementesSilent(int amount)
    {
        sementes = Mathf.Max(0, sementes + amount);
        if (amount > 0) totalSementesCollected += amount;
        // SeedsChanged NOT fired — efeito silencioso.
    }

    /// <summary>
    /// Ajusta o saldo de Ecos Perdidos. Se "amount" for positivo, soma também ao
    /// total recolhido (nunca desce). Use valores negativos para gastar (ex: compra
    /// de Sussurros da Terra). PlayerProgress garante que o saldo nunca fica negativo.
    /// </summary>
    public void GiveEcosPerdidos(int amount)
    {
        ecosPerdidos = Mathf.Max(0, ecosPerdidos + amount);
        if (amount > 0) totalEcosPerdidosCollected += amount;
        EcosPerdidosChanged?.Invoke(ecosPerdidos);
    }

    /// <summary>
    /// Tenta gastar "amount" de Ecos Perdidos. Devolve false se o saldo for insuficiente.
    /// Use em conjunto com "ecosPerdidos >= amount" antes de mostrar opção de compra.
    /// </summary>
    public bool TrySpendEcosPerdidos(int amount)
    {
        if (amount <= 0) return true;
        if (ecosPerdidos < amount) return false;
        GiveEcosPerdidos(-amount);
        return true;
    }

    public bool HasEcosPerdidos(int amount) => ecosPerdidos >= amount;

    /// <summary>Ajusta o saldo de Runas de Gaia disponíveis. Se "amount" for positivo, soma também ao total recolhido (runasDeGaia recolhidas, para estatísticas/registo — nunca desce).</summary>
    public void GiveRunasDeGaia(int amount)
    {
        runasDeGaia = Mathf.Max(0, runasDeGaia + amount);
        if (amount > 0) totalRunasDeGaiaCollected += amount;
        RunasChanged?.Invoke(runasDeGaia, totalRunasDeGaiaCollected);
    }

    /// <summary>
    /// Concede Runas de Apolo (recompensa exclusiva da Provação de Apolo).
    /// Ao atingir 6, o Emblema de Apolo é desbloqueado pelo
    /// <see cref="EmblemManager"/> (verificação automática após GrantReward).
    /// </summary>
    /// <summary>Máximo de Runas de Apolo (uma por Provação de Apolo no jogo).</summary>
    public const int MaxRunasDeApolo = 6;

    public void GiveRunasDeApolo(int amount)
    {
        if (amount <= 0) return;
        // Task #28: clamp a MaxRunasDeApolo para nunca ultrapassar as 6 Provações.
        runasDeApolo = Mathf.Clamp(runasDeApolo + amount, 0, MaxRunasDeApolo);
        RunasDeApoloChanged?.Invoke(runasDeApolo);
    }

    /// <summary>Disparado quando o total de Runas de Apolo muda (UI / EmblemManager).</summary>
    public event System.Action<int> RunasDeApoloChanged;

    /// <summary>
    /// GDD: o Broto de Vida é uma cura pequena automática — ao ser recolhido
    /// (amount > 0), cura "amount" corações de imediato, além de actualizar o
    /// contador/estatística (brotosDeVida/totalBrotosDeVidaCollected, usados
    /// também como recurso gastável via Action_GiveResource/TakeResource).
    /// É a principal fonte de cura em Modo Difícil, onde a regeneração
    /// automática (PlayerHealthRegen) está desactivada.
    /// </summary>
    public void GiveBrotosDeVida(int amount)
    {
        brotosDeVida = Mathf.Max(0, brotosDeVida + amount);
        if (amount > 0)
        {
            totalBrotosDeVidaCollected += amount;
            Heal(amount);
        }
    }

    /// <summary>Adiciona Fragmentos Vitais e converte automaticamente em corações extra quando atingir "fragmentsPerHeart" (até ao limite MaxHeartsCap — GDD: 12 corações).</summary>
    public void GiveFragmentosVitais(int amount)
    {
        fragmentosVitais = Mathf.Max(0, fragmentosVitais + amount);
        if (amount > 0)
        {
            totalFragmentosVitaisCollected += amount;
            TryConvertFragments();
        }
    }

    /// <summary>Converte Fragmentos Vitais acumulados em +1 coração (recipiente) de cada vez, enquanto houver fragmentos suficientes e "maxHearts" não tiver atingido "MaxHeartsCap" (12). O novo recipiente já nasce cheio.</summary>
    private void TryConvertFragments()
    {
        if (fragmentsPerHeart <= 0) return;

        while (maxHearts < MaxHeartsCap && fragmentosVitais >= fragmentsPerHeart)
        {
            fragmentosVitais -= fragmentsPerHeart;
            maxHearts++;
            currentHearts = Mathf.Min(currentHearts + 1, maxHearts);
            HealthChanged?.Invoke(currentHearts, maxHearts);
            HeartContainerGained?.Invoke();
        }
    }

    // ---------------- Itens (Etapa 4.2 — inventário com quantidades) ----------------

    public bool HasItem(string itemId) => GetItemQuantity(itemId) > 0;
    public bool HasItem(ItemData item) => item != null && HasItem(item.itemId);

    /// <summary>Quantidade actual de "itemId" no inventário (0 se não existir).</summary>
    public int GetItemQuantity(string itemId)
    {
        if (string.IsNullOrEmpty(itemId)) return 0;

        for (int i = 0; i < _inventory.Count; i++)
            if (_inventory[i].itemId == itemId) return _inventory[i].quantity;

        return 0;
    }

    public int GetItemQuantity(ItemData item) => item != null ? GetItemQuantity(item.itemId) : 0;

    /// <summary>
    /// Adiciona "amount" de "itemId" ao inventário, sem exceder "maxQuantity"
    /// (0 = sem limite). Devolve a quantidade efectivamente adicionada.
    /// </summary>
    public int AddItem(string itemId, int amount = 1, int maxQuantity = 0)
    {
        if (string.IsNullOrEmpty(itemId) || amount <= 0) return 0;

        var entry = GetOrCreateEntry(itemId);
        int newQuantity = maxQuantity > 0
            ? Mathf.Min(maxQuantity, entry.quantity + amount)
            : entry.quantity + amount;

        int added = newQuantity - entry.quantity;
        entry.quantity = newQuantity;
        return added;
    }

    /// <summary>Adiciona "amount" de "item", respeitando ItemData.maxQuantity, e regista-o como colectado se "savedAsCollected" (Etapa 4.3). Devolve a quantidade efectivamente adicionada.</summary>
    public int AddItem(ItemData item, int amount = 1)
    {
        if (item == null) return 0;

        int added = AddItem(item.itemId, amount, item.maxQuantity);

        if (item.savedAsCollected && added > 0)
            MarkSpecialItemCollected(item.itemId);

        return added;
    }

    /// <summary>Remove até "amount" de "itemId" do inventário. Devolve a quantidade efectivamente removida.</summary>
    public int RemoveItem(string itemId, int amount = 1)
    {
        if (string.IsNullOrEmpty(itemId) || amount <= 0) return 0;

        for (int i = 0; i < _inventory.Count; i++)
        {
            if (_inventory[i].itemId != itemId) continue;

            int removed = Mathf.Min(_inventory[i].quantity, amount);
            _inventory[i].quantity -= removed;

            if (_inventory[i].quantity <= 0) _inventory.RemoveAt(i);
            return removed;
        }

        return 0;
    }

    public int RemoveItem(ItemData item, int amount = 1) => item != null ? RemoveItem(item.itemId, amount) : 0;

    /// <summary>Compatibilidade (pré-Etapa 4.2): adiciona 1 unidade de "itemId" (sem limite de quantidade).</summary>
    public void GiveItem(string itemId) => AddItem(itemId, 1);

    /// <summary>Compatibilidade (pré-Etapa 4.2): adiciona 1 unidade de "item" (respeita maxQuantity/savedAsCollected).</summary>
    public void GiveItem(ItemData item) => AddItem(item, 1);

    private InventoryEntry GetOrCreateEntry(string itemId)
    {
        for (int i = 0; i < _inventory.Count; i++)
            if (_inventory[i].itemId == itemId) return _inventory[i];

        var created = new InventoryEntry { itemId = itemId };
        _inventory.Add(created);
        return created;
    }

