    /// <summary>Melhor (menor) tempo registado para "challengeId", ou -1 se nunca foi registado um tempo.</summary>
    public float GetChallengeBestTime(string challengeId)
    {
        if (string.IsNullOrEmpty(challengeId)) return -1f;

        foreach (var record in _challengeRecords)
            if (record != null && record.challengeId == challengeId) return record.bestTimeSeconds;

        return -1f;
    }

    /// <summary>
    /// Regista "timeSeconds" para "challengeId" se for o primeiro registo ou um
    /// tempo melhor (menor) do que o anterior. Devolve true se um novo recorde
    /// foi gravado (útil para o HUD mostrar "Novo Recorde!").
    /// </summary>
    public bool TryRecordChallengeTime(string challengeId, float timeSeconds)
    {
        if (string.IsNullOrEmpty(challengeId)) return false;

        foreach (var record in _challengeRecords)
        {
            if (record != null && record.challengeId == challengeId)
            {
                if (timeSeconds >= record.bestTimeSeconds) return false;
                record.bestTimeSeconds = timeSeconds;
                return true;
            }
        }

        _challengeRecords.Add(new ChallengeRecord { challengeId = challengeId, bestTimeSeconds = timeSeconds });
        return true;
    }

