    /// <summary>Versão actual da estrutura de save (ver SaveData.saveVersion).</summary>
    public const int CurrentSaveVersion = 1;

    /// <summary>Copia o estado actual para "data" (usado por SaveManager ao gravar).</summary>
    public void CaptureTo(SaveData data)
    {
        data.saveVersion = CurrentSaveVersion;

        data.currentHearts = currentHearts;
        data.maxHearts = maxHearts;

        data.sementes = sementes;
        data.runasDeGaia = runasDeGaia;
        data.totalRunasDeGaiaCollected = totalRunasDeGaiaCollected;
        data.brotosDeVida = brotosDeVida;
        data.fragmentosVitais = fragmentosVitais;
        data.runasDeApolo = runasDeApolo;

        data.ecosPerdidos = ecosPerdidos;
        data.totalEcosPerdidosCollected = totalEcosPerdidosCollected;

        data.inventory = new List<InventoryEntry>();
        foreach (var entry in _inventory)
            data.inventory.Add(new InventoryEntry { itemId = entry.itemId, quantity = entry.quantity });

        data.equippedItemId = equippedItemId;

        data.collectedSpecialItemIds = new List<string>(_collectedSpecialItemIds);
        data.defeatedEnemyIds = new List<string>(_defeatedEnemyIds);
        data.collectedPickupIds = new List<string>(_collectedPickupIds);

        data.collectedMelodyIds = new List<string>(_collectedMelodyIds);
        data.completedChallengeIds = new List<string>(_completedChallengeIds);

        data.challengeRecords = new List<ChallengeRecord>();
        foreach (var record in _challengeRecords)
            if (record != null) data.challengeRecords.Add(new ChallengeRecord { challengeId = record.challengeId, bestTimeSeconds = record.bestTimeSeconds });

        data.totalSementesCollected = totalSementesCollected;
        data.totalFragmentosVitaisCollected = totalFragmentosVitaisCollected;
        data.totalBrotosDeVidaCollected = totalBrotosDeVidaCollected;
        data.totalSussurrosCollected = totalSussurrosCollected;
        data.totalChestsOpenedGlobal = totalChestsOpenedGlobal;

        data.isNewGamePlus = isNewGamePlus;

        data.freedAnimalIds = new List<string>(_freedAnimalIds);
        data.unlockedUpgradeIds = new List<string>(_unlockedUpgradeIds);
        data.enabledUpgradeIds = new List<string>(_enabledUpgradeIds);

        // Nota: o Modo Difícil ("Juramento Difícil") já não tem campo próprio —
        // é derivado de _enabledUpgradeIds (ver IsHardModeActive), já guardado acima.
        data.lastCheckpointId = lastCheckpointId;

        data.areaProgress = new List<AreaProgress>();
        foreach (var ap in areaProgress)
            data.areaProgress.Add(new AreaProgress
            {
                areaId = ap.areaId,
                deaths = ap.deaths,
                visited = ap.visited,
                opened = ap.opened,
                runasFound = ap.runasFound,
                npcsRescued = ap.npcsRescued,
                rescuedNpcIds = new List<string>(ap.rescuedNpcIds),
                whispersFound = ap.whispersFound,
                whispersDelivered = ap.whispersDelivered,
                chestsFound = ap.chestsFound,
                fragmentsFound = ap.fragmentsFound,
                ecosPerdidosFound = ap.ecosPerdidosFound,
                challengeCompleted = ap.challengeCompleted,
                challengeDiscovered = ap.challengeDiscovered,
                melodiesFound = ap.melodiesFound,
                sussurrosDaTerraOuvidos = new List<string>(ap.sussurrosDaTerraOuvidos)
            });

        data.defeatedBossWorldIds = new List<string>(defeatedBossWorldIds);
        data.pendingPostBossReturnWorldIds = new List<string>(pendingPostBossReturnWorldIds);

        data.worldProgress = new List<WorldProgress>();
        foreach (var wp in worldProgress)
            data.worldProgress.Add(new WorldProgress { worldId = wp.worldId, totalsDiscovered = wp.totalsDiscovered });

        data.obtainedClueIds = new List<string>(_obtainedClueIds);
        data.heardRumorIds = new List<string>(_heardRumorIds);
        data.foundRumorIds = new List<string>(_foundRumorIds);

        data.unlockedAreaIds = new List<string>(unlockedAreaIds);
        data.discoveredBossWorldIds = new List<string>(discoveredBossWorldIds);
        data.bossUnlockAnimationPlayedWorldIds = new List<string>(bossUnlockAnimationPlayedWorldIds);
        data.apoloAreaUnlockAnimationPlayed = apoloAreaUnlockAnimationPlayed;

        // Snapshots activos (ex: sequência de roubo em curso).
        data.activeSnapshots = new List<SaveData.SnapshotEntry>();
        foreach (var kv in _snapshots)
            data.activeSnapshots.Add(new SaveData.SnapshotEntry { key = kv.Key, snapshot = kv.Value });
    }

    /// <summary>Restaura o estado a partir de "data" (usado por SaveManager ao carregar).</summary>
    public void RestoreFrom(SaveData data)
    {
        if (data == null) return;

        maxHearts = Mathf.Min(data.maxHearts, MaxHeartsCap);
        currentHearts = Mathf.Clamp(data.currentHearts, 0, maxHearts);

        sementes = data.sementes;
        runasDeGaia = data.runasDeGaia;
        totalRunasDeGaiaCollected = data.totalRunasDeGaiaCollected;
        brotosDeVida = data.brotosDeVida;
        fragmentosVitais = data.fragmentosVitais;
        runasDeApolo = Mathf.Clamp(data.runasDeApolo, 0, MaxRunasDeApolo);

        ecosPerdidos = data.ecosPerdidos;
        totalEcosPerdidosCollected = data.totalEcosPerdidosCollected;

        _inventory.Clear();
        if (data.inventory != null)
            foreach (var entry in data.inventory)
                _inventory.Add(new InventoryEntry { itemId = entry.itemId, quantity = entry.quantity });

        equippedItemId = data.equippedItemId;

        _collectedSpecialItemIds.Clear();
        if (data.collectedSpecialItemIds != null) _collectedSpecialItemIds.AddRange(data.collectedSpecialItemIds);

        _defeatedEnemyIds.Clear();
        if (data.defeatedEnemyIds != null) _defeatedEnemyIds.AddRange(data.defeatedEnemyIds);

        _collectedPickupIds.Clear();
        if (data.collectedPickupIds != null) _collectedPickupIds.AddRange(data.collectedPickupIds);

        _collectedMelodyIds.Clear();
        if (data.collectedMelodyIds != null) _collectedMelodyIds.AddRange(data.collectedMelodyIds);

        _completedChallengeIds.Clear();
        if (data.completedChallengeIds != null) _completedChallengeIds.AddRange(data.completedChallengeIds);

        _challengeRecords.Clear();
        if (data.challengeRecords != null)
            foreach (var record in data.challengeRecords)
                if (record != null) _challengeRecords.Add(new ChallengeRecord { challengeId = record.challengeId, bestTimeSeconds = record.bestTimeSeconds });

        totalSementesCollected = data.totalSementesCollected;
        totalFragmentosVitaisCollected = data.totalFragmentosVitaisCollected;
        totalBrotosDeVidaCollected = data.totalBrotosDeVidaCollected;
        totalSussurrosCollected = data.totalSussurrosCollected;
        totalChestsOpenedGlobal = data.totalChestsOpenedGlobal;

        isNewGamePlus = data.isNewGamePlus;

        _freedAnimalIds.Clear();
        if (data.freedAnimalIds != null) _freedAnimalIds.AddRange(data.freedAnimalIds);

        _unlockedUpgradeIds.Clear();
        if (data.unlockedUpgradeIds != null) _unlockedUpgradeIds.AddRange(data.unlockedUpgradeIds);

        _enabledUpgradeIds.Clear();
        if (data.enabledUpgradeIds != null) _enabledUpgradeIds.AddRange(data.enabledUpgradeIds);

        // Nota: o Modo Difícil ("Juramento Difícil") já não tem campo próprio —
        // é derivado de _enabledUpgradeIds (ver IsHardModeActive), já restaurado acima.
        lastCheckpointId = data.lastCheckpointId;

        areaProgress.Clear();
        if (data.areaProgress != null)
            foreach (var ap in data.areaProgress)
                areaProgress.Add(new AreaProgress
                {
                    areaId = ap.areaId,
                    deaths = ap.deaths,
                    visited = ap.visited,
                    opened = ap.opened,
                    runasFound = ap.runasFound,
                    npcsRescued = ap.npcsRescued,
                    rescuedNpcIds = ap.rescuedNpcIds != null ? new List<string>(ap.rescuedNpcIds) : new List<string>(),
                    whispersFound = ap.whispersFound,
                    whispersDelivered = ap.whispersDelivered,
                    chestsFound = ap.chestsFound,
                    fragmentsFound = ap.fragmentsFound,
                    ecosPerdidosFound = ap.ecosPerdidosFound,
                    challengeCompleted = ap.challengeCompleted,
                    challengeDiscovered = ap.challengeDiscovered,
                    melodiesFound = ap.melodiesFound,
                    sussurrosDaTerraOuvidos = ap.sussurrosDaTerraOuvidos != null ? new List<string>(ap.sussurrosDaTerraOuvidos) : new List<string>()
                });

        // Migração: saves versão 0 (sem rescuedNpcIds) — aceitar inconsistência.
        // Os rescuedNpcIds ficam vazios; novas chamadas a AddNpcRescued passam a
        // funcionar correctamente com idempotência. Salvar novamente para converter.
        // (Nenhuma acção extra necessária — os IDs são preenchidos ao resgatar NPCs.)

        defeatedBossWorldIds.Clear();
        if (data.defeatedBossWorldIds != null) defeatedBossWorldIds.AddRange(data.defeatedBossWorldIds);

        pendingPostBossReturnWorldIds.Clear();
        if (data.pendingPostBossReturnWorldIds != null) pendingPostBossReturnWorldIds.AddRange(data.pendingPostBossReturnWorldIds);

        worldProgress.Clear();
        if (data.worldProgress != null)
            foreach (var wp in data.worldProgress)
                worldProgress.Add(new WorldProgress { worldId = wp.worldId, totalsDiscovered = wp.totalsDiscovered });

        _obtainedClueIds.Clear();
        if (data.obtainedClueIds != null) _obtainedClueIds.AddRange(data.obtainedClueIds);

        _heardRumorIds.Clear();
        if (data.heardRumorIds != null) _heardRumorIds.AddRange(data.heardRumorIds);

        _foundRumorIds.Clear();
        if (data.foundRumorIds != null) _foundRumorIds.AddRange(data.foundRumorIds);

        unlockedAreaIds.Clear();
        if (data.unlockedAreaIds != null) unlockedAreaIds.AddRange(data.unlockedAreaIds);

        discoveredBossWorldIds.Clear();
        if (data.discoveredBossWorldIds != null) discoveredBossWorldIds.AddRange(data.discoveredBossWorldIds);

        bossUnlockAnimationPlayedWorldIds.Clear();
        if (data.bossUnlockAnimationPlayedWorldIds != null) bossUnlockAnimationPlayedWorldIds.AddRange(data.bossUnlockAnimationPlayedWorldIds);

        apoloAreaUnlockAnimationPlayed = data.apoloAreaUnlockAnimationPlayed;

        // Snapshots activos (ex: sequência de roubo em curso) — espelho de CaptureTo.
        _snapshots.Clear();
        if (data.activeSnapshots != null)
        {
            foreach (var entry in data.activeSnapshots)
            {
                if (entry != null && !string.IsNullOrEmpty(entry.key))
                    _snapshots[entry.key] = entry.snapshot;
            }
        }
    }
}

