/// <summary>Entrada do inventário: um item (por ID) e a quantidade possuída.</summary>
[System.Serializable]
public class InventoryEntry
{
    public string itemId;
    public int quantity;
}

/// <summary>
/// Progresso do jogador numa área específica (contagens de coleccionáveis,
/// NPCs resgatados, desafio, mortes, etc.). Uma entrada por área visitada —
/// ver PlayerProgress.AreaProgress.cs para os métodos de acesso.
/// </summary>
[System.Serializable]
public class AreaProgress
{
    public string areaId;

    public int deaths;
    public bool visited;
    public bool opened;

    public int runasFound;

    public int npcsRescued;
    public List<string> rescuedNpcIds = new List<string>();

    public int whispersFound;
    public int whispersDelivered;

    public int chestsFound;
    public int fragmentsFound;
    public int ecosPerdidosFound;

    public bool challengeCompleted;
    public bool challengeDiscovered;

    public int melodiesFound;
    public List<string> sussurrosDaTerraOuvidos = new List<string>();
}

/// <summary>
/// Progresso do jogador num mundo (ver PlayerProgress.WorldProgress.cs).
/// "totalsDiscovered" = o jogador já descobriu quantos Runas/Animais/NPCs/
/// Sussurros/Missões existem neste mundo (mostra números reais no Mapa-Múndi
/// em vez de "?").
/// </summary>
[System.Serializable]
public class WorldProgress
{
    public string worldId;
    public bool totalsDiscovered;
}

/// <summary>
/// Fotografia parcial do estado do jogador (recursos, corações, inventário,
/// item equipado, animais libertados, formas bloqueadas) usada pelas acções
/// Action_SavePlayerSnapshot / Action_RestorePlayerSnapshot (ex: sequência de
/// roubo). Os pares has*/valor permitem guardar/restaurar só o que foi
/// seleccionado no Inspector — ver StatusSnapshotActions.cs.
/// </summary>
[System.Serializable]
public class PlayerSnapshot
{
    public bool hasSementes;
    public int sementes;

    public bool hasRunasDeGaia;
    public int runasDeGaia;

    public bool hasEcosPerdidos;
    public int ecosPerdidos;

    public bool hasBrotosDeVida;
    public int brotosDeVida;

    public bool hasCurrentHearts;
    public int currentHearts;

    public bool hasMaxHearts;
    public int maxHearts;

    public bool hasInventory;
    public List<InventoryEntry> inventory = new List<InventoryEntry>();

    public bool hasEquippedItem;
    public string equippedItemId;

    public bool hasFreedAnimals;
    public List<string> freedAnimalIds = new List<string>();

    public bool hasLockedForms;
    public List<string> lockedFormIds = new List<string>();
}
